$((function(){"use strict";var url="/administration/hotels/main/upload";$("#fileupload").fileupload({url:url,dataType:"json",done:function(e,data){notify(data.files[0].name+" successfully uploaded","success");$(".dv-hotel-photos > span").each((function(){if(!$(this).find("img").length){$(this).append('<img height="50" width="50" src="'+URL.createObjectURL(data.files[0])+'"/>');$(this).append('<input type="hidden" class="dv-create-hotel-image-orig-name" value="'+data.files[0].name+'"/>');$(this).append('<input type="hidden" class="dv-create-hotel-image-file-name" value="'+data.result+'"/>')}}))},progressall:function(e,data){var progress=parseInt(data.loaded/data.total*100,10);$("#progress .progress-bar").css("width",progress+"%")}}).prop("disabled",!$.support.fileInput).parent().addClass($.support.fileInput?undefined:"disabled")}));